import{readFile}from"node:fs/promises";import fg from"fast-glob";import{partition}from"./array.js";import{ConfigurationError}from"./errors.js";import{getPackageName}from"./package-name.js";import{join}from"./path.js";export default async function mapWorkspaces(a,o){const[e,r]=partition(o,a=>a.match(/^!/)),t=new Map,n=new Set;if(0===r.length&&0===e.length)return[t,n];const i=r.map(a=>join(a,"package.json")),s=await fg.glob(i,{cwd:a,ignore:["**/node_modules/**",...e.map(a=>a.slice(1))]});for(const o of s.sort()){const e="package.json"===o?".":o.replace(/\/package\.json$/,""),r=join(a,e),i=join(a,o);try{const a=await readFile(i,"utf8"),o=JSON.parse(a),s=getPackageName(o,r),m={dir:r,name:e,pkgName:s,manifestPath:i,manifestStr:a,manifest:o};if(t.set(e,m),!s)throw new ConfigurationError(`Missing package name in ${i}`);n.add(s)}catch(a){if("ENOENT"!==a?.code)throw a;debugLog("*",`Unable to load package.json for ${e}`)}}return[t,n]}